sql:
SELECT station_id, COUNT(tag_name) AS tag_count
FROM station_tags
GROUP BY station_id;

external_knowledge:
; The term 'tag details' refers to the station_id, tag_name, and created_date of each tag; 
; The 'number of tags per station' refers to the count of tags associated with each station_id; 
; The 'frequency of each tag' refers to the count of times each tag_name is used across all stations; 
; The 'age of tags' is calculated as the difference between the current date and the tag creation date in days, using the JULIANDAY function for date calculations.
